@model VehicleFormVm
<section class="panel vehicle-edit-layout">
    <h1>Uredi vozilo</h1>
    <div class="vehicle-edit-grid">
        <div>
            <partial name="_FormPartial" />
        </div>
        <div class="attachment-panel">
            <h2>Dokumenti vozila</h2>
            <form id="attachmentDz"
                  asp-controller="Vehicle"
                  asp-action="UploadAttachment"
                  asp-route-vehicleId="@Model.Id"
                  enctype="multipart/form-data"
                  class="dropzone attachment-dropzone">
            </form>
            <div id="attachmentList"></div>
        </div>
    </div>
</section>

@section Scripts {
    <partial name="_ValidationScriptsPartial" />
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/dropzone/5.9.3/min/dropzone.min.css" />
    <script src="https://cdnjs.cloudflare.com/ajax/libs/dropzone/5.9.3/min/dropzone.min.js"></script>
    <script>
        Dropzone.autoDiscover = false;
        const vehicleId = @Model.Id;

        function loadAttachments() {
            $("#attachmentList").load("@Url.Action("GetAttachments", "Vehicle", new { vehicleId = Model.Id })");
        }

        $(function () {
            loadAttachments();
            const dz = new Dropzone("#attachmentDz", {
                paramName: "file",
                maxFilesize: 10,
                acceptedFiles: ".pdf,.jpg,.jpeg,.png",
                success: function () { loadAttachments(); }
            });
        });

        function deleteAttachment(id) {
            $.post("@Url.Action("DeleteAttachment", "Vehicle")", { id: id }, function () {
                loadAttachments();
            });
        }
    </script>
}

using System.Security.Claims;
using System.Text.Encodings.Web;
using Microsoft.AspNetCore.Authentication;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Options;

namespace CarRent.Web.IntegrationTests;

public sealed class TestAuthHandler : AuthenticationHandler<AuthenticationSchemeOptions>
{
    public const string SchemeName = "TestAuth";
    public const string RoleHeader = "X-Test-Role";

    public TestAuthHandler(
        IOptionsMonitor<AuthenticationSchemeOptions> options,
        ILoggerFactory logger,
        UrlEncoder encoder)
        : base(options, logger, encoder)
    {
    }

    protected override Task<AuthenticateResult> HandleAuthenticateAsync()
    {
        if (!Request.Headers.TryGetValue(RoleHeader, out var roleValues) || string.IsNullOrWhiteSpace(roleValues))
            return Task.FromResult(AuthenticateResult.NoResult());

        var role = roleValues.ToString();
        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, $"test-{role.ToLowerInvariant()}@carrent.test"),
            new(ClaimTypes.Role, role)
        };

        var identity = new ClaimsIdentity(claims, SchemeName);
        var principal = new ClaimsPrincipal(identity);
        var ticket = new AuthenticationTicket(principal, SchemeName);
        return Task.FromResult(AuthenticateResult.Success(ticket));
    }
}

using CarRent.DAL;
using Microsoft.AspNetCore.Authentication;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Mvc.Testing;
using Microsoft.AspNetCore.TestHost;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.DependencyInjection.Extensions;

namespace CarRent.Web.IntegrationTests;

public sealed class CarRentWebApplicationFactory : WebApplicationFactory<Program>
{
    private readonly string _dbName = $"CarRentTests_{Guid.NewGuid():N}";

    protected override void ConfigureWebHost(IWebHostBuilder builder)
    {
        builder.UseEnvironment("Development");

        builder.ConfigureAppConfiguration((_, config) =>
        {
            config.AddInMemoryCollection(new Dictionary<string, string?>
            {
                ["DatabaseProvider"] = "Sqlite",
                ["ConnectionStrings:CarRentDb"] = "Data Source=:memory:",
                ["Authentication:Google:ClientId"] = "test-client-id",
                ["Authentication:Google:ClientSecret"] = "test-client-secret"
            });
        });

        builder.ConfigureTestServices(services =>
        {
            services.RemoveAll(typeof(DbContextOptions<CarRentDbContext>));
            services.RemoveAll(typeof(CarRentDbContext));

            services.AddDbContext<CarRentDbContext>(options =>
                options.UseInMemoryDatabase(_dbName));

            services.AddAuthentication(options =>
            {
                options.DefaultAuthenticateScheme = TestAuthHandler.SchemeName;
                options.DefaultChallengeScheme = TestAuthHandler.SchemeName;
            }).AddScheme<AuthenticationSchemeOptions, TestAuthHandler>(TestAuthHandler.SchemeName, _ => { });
        });
    }

    protected override IHost CreateHost(IHostBuilder builder)
    {
        var host = base.CreateHost(builder);
        using var scope = host.Services.CreateScope();
        var db = scope.ServiceProvider.GetRequiredService<CarRentDbContext>();
        db.Database.EnsureCreated();
        return host;
    }
}

namespace CarRent.Web.IntegrationTests;

public static class ApiTestClientExtensions
{
    public static HttpClient AsRole(this HttpClient client, string role)
    {
        client.DefaultRequestHeaders.Remove(TestAuthHandler.RoleHeader);
        client.DefaultRequestHeaders.Add(TestAuthHandler.RoleHeader, role);
        return client;
    }

    public static HttpClient AsAnonymous(this HttpClient client)
    {
        client.DefaultRequestHeaders.Remove(TestAuthHandler.RoleHeader);
        return client;
    }
}

