using System.Security.Claims;
using CarRent.Model.Entities;
using Microsoft.AspNetCore.Identity;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.RazorPages;

namespace CarRent.Web.Areas.Identity.Pages.Account;

public class ExternalLoginModel : PageModel
{
    private readonly SignInManager<AppUser> _signInManager;
    private readonly UserManager<AppUser> _userManager;
    private readonly ILogger<ExternalLoginModel> _logger;

    public ExternalLoginModel(
        SignInManager<AppUser> signInManager,
        UserManager<AppUser> userManager,
        ILogger<ExternalLoginModel> logger)
    {
        _signInManager = signInManager;
        _userManager = userManager;
        _logger = logger;
    }

    public IActionResult OnGet() => RedirectToPage("./Login");

    public IActionResult OnPost(string provider, string? returnUrl = null)
    {
        var redirectUrl = Url.Page("./ExternalLogin", pageHandler: "Callback", values: new { returnUrl });
        var properties = _signInManager.ConfigureExternalAuthenticationProperties(provider, redirectUrl);
        return new ChallengeResult(provider, properties);
    }

    public async Task<IActionResult> OnGetCallbackAsync(string? returnUrl = null, string? remoteError = null)
    {
        returnUrl ??= Url.Content("~/");
        if (!string.IsNullOrEmpty(remoteError))
        {
            ErrorMessage = $"Greška vanjskog providera: {remoteError}";
            return RedirectToPage("./Login", new { ReturnUrl = returnUrl });
        }

        var info = await _signInManager.GetExternalLoginInfoAsync();
        if (info is null)
            return RedirectToPage("./Login", new { ReturnUrl = returnUrl });

        var signInResult = await _signInManager.ExternalLoginSignInAsync(
            info.LoginProvider, info.ProviderKey, isPersistent: false);
        if (signInResult.Succeeded)
            return LocalRedirect(returnUrl);

        var email = info.Principal.FindFirstValue(ClaimTypes.Email);
        if (string.IsNullOrWhiteSpace(email))
        {
            ErrorMessage = "Vanjski račun nema email. Prijava nije moguća.";
            return RedirectToPage("./Login", new { ReturnUrl = returnUrl });
        }

        var user = await _userManager.FindByEmailAsync(email);
        if (user is null)
        {
            ErrorMessage = "Nemate račun na platformi. Administrator mora kreirati korisnika prije prijave.";
            return RedirectToPage("./Login", new { ReturnUrl = returnUrl });
        }

        var linkResult = await _userManager.AddLoginAsync(user, info);
        if (!linkResult.Succeeded)
        {
            ErrorMessage = "Google račun nije moguće povezati s postojećim korisnikom.";
            return RedirectToPage("./Login", new { ReturnUrl = returnUrl });
        }

        await _signInManager.SignInAsync(user, isPersistent: false);
        _logger.LogInformation("Korisnik {Email} prijavljen putem {Provider}.", email, info.LoginProvider);
        return LocalRedirect(returnUrl);
    }

    [TempData]
    public string? ErrorMessage { get; set; }
}

using CarRent.Model.Entities;
using Microsoft.AspNetCore.Identity;

namespace CarRent.Web.Middleware;

public sealed class PendingRoleMiddleware(RequestDelegate next)
{
    private static readonly string[] AllowedPrefixes =
    [
        "/Identity/Account/Login",
        "/Identity/Account/Logout",
        "/Identity/Account/ExternalLogin",
        "/Identity/Account/PendingAccess",
        "/css/",
        "/js/",
        "/lib/",
        "/uploads/",
        "/favicon"
    ];

    public async Task InvokeAsync(HttpContext context, UserManager<AppUser> userManager)
    {
        if (context.User.Identity?.IsAuthenticated == true)
        {
            var path = context.Request.Path.Value ?? string.Empty;
            if (!IsAllowed(path))
            {
                var user = await userManager.GetUserAsync(context.User);
                if (user is not null)
                {
                    var roles = await userManager.GetRolesAsync(user);
                    if (roles.Count == 0 &&
                        !path.StartsWith("/Identity/Account/PendingAccess", StringComparison.OrdinalIgnoreCase))
                    {
                        context.Response.Redirect("/Identity/Account/PendingAccess");
                        return;
                    }
                }
            }
        }

        await next(context);
    }

    private static bool IsAllowed(string path) =>
        AllowedPrefixes.Any(prefix => path.StartsWith(prefix, StringComparison.OrdinalIgnoreCase));
}

using CarRent.Model.Entities;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Identity;
