        <div style="font-size:80px;opacity:0.5">🚗</div>
    </div>
    <div class="hero-info">
        <div class="hero-eyebrow">Vozilo</div>
        <h1 class="hero-title" style="font-size:26px">@Model.Brand @Model.Model</h1>
        <div class="hero-reg">@Model.RegistrationNumber</div>
        <div class="hero-stats" style="display:flex;flex-wrap:wrap;gap:6px">
            <span class="chip @(Model.IsActive ? "chip-completed" : "chip-cancelled")">@(Model.IsActive ? "Aktivno" : "Neaktivno")</span>
            <span style="font-size:12px;color:var(--muted);padding:4px 10px;border:1px solid var(--line);border-radius:20px">@Model.Type · @Model.Year</span>
            <span style="font-size:12px;color:var(--muted);padding:4px 10px;border:1px solid var(--line);border-radius:20px">🏢 @branchName</span>
        </div>
        <div class="hero-price">@Model.DailyPrice.ToString("N0") <span style="font-size:14px;font-weight:400;color:var(--muted)">EUR/dan</span></div>
        <div class="hero-actions vehicle-hero-actions">
            <a asp-action="Edit" asp-route-id="@Model.Id" asp-route-returnUrl="@returnUrl" class="btn btn-primary btn-sm">Uredi vozilo</a>
            @if (fromFleet && !string.IsNullOrEmpty(returnUrl))
            {
                <a href="@returnUrl" class="btn btn-secondary btn-sm">← Vozni park</a>
            }
            else if (User.IsInRole("Admin"))
            {
                <a asp-action="Index" class="btn btn-secondary btn-sm">← Lista vozila</a>
            }
            else
            {
                <a asp-controller="Fleet" asp-action="Index" class="btn btn-secondary btn-sm">← Vozni park</a>
            }
        </div>
    </div>
</div>

<div class="tabs-bar" role="tablist">
    <button type="button" class="tab-btn active" data-tab="pregled">Pregled</button>
    <button type="button" class="tab-btn" data-tab="rezervacije">Rezervacije (@Model.Reservations.Count)</button>
    <button type="button" class="tab-btn" data-tab="servisi">Servisi (@Model.ServiceRecords.Count)</button>
    <button type="button" class="tab-btn" data-tab="dokumenti">Dokumenti (@attachments.Count)</button>
</div>

<div id="pregled" class="tab-panel active">
    <div class="tab-toolbar">
        <h3 class="tab-toolbar-title">Osnovni podaci</h3>
        <a asp-action="Edit" asp-route-id="@Model.Id" asp-route-returnUrl="@returnUrl" class="btn btn-primary btn-sm">Uredi vozilo</a>
    </div>
    <div class="detail-grid">
        <div class="glass">
            <div class="form-section-title">Osnovno</div>
            <div class="detail-row"><span>Registracija</span><span>@Model.RegistrationNumber</span></div>
            <div class="detail-row"><span>Kilometraža</span><span>@Model.MileageKm km</span></div>
            <div class="detail-row"><span>Poslovnica</span><span>@branchName</span></div>
        </div>
        <div class="glass">
            <div class="form-section-title">Cijena i status</div>
            <div class="detail-row"><span>Cijena / dan</span><span>@Model.DailyPrice EUR</span></div>
            <div class="detail-row"><span>Godina</span><span>@Model.Year</span></div>
            <div class="detail-row"><span>Tip</span><span>@Model.Type</span></div>
        </div>
    </div>
</div>

<div id="rezervacije" class="tab-panel">
    <div class="tab-toolbar">
        <h3 class="tab-toolbar-title">Rezervacije vozila</h3>
        <a asp-controller="Reservation" asp-action="Create" asp-route-vehicleId="@Model.Id" asp-route-returnUrl="@vehicleReturn" class="btn btn-primary btn-sm">+ Nova rezervacija</a>
    </div>
    @if (!Model.Reservations.Any())
    {
        <p class="tab-empty">Nema rezervacija za ovo vozilo.</p>
    }
    else
    {
        <div class="table-wrap">
            <table class="data-table">
                <thead><tr><th>ID</th><th>Kupac</th><th>Period</th><th>Status</th><th>Akcije</th></tr></thead>
                <tbody>
                @foreach (var r in Model.Reservations.OrderByDescending(x => x.StartDate))
                {
                    <tr>
                        <td><span class="tbl-id">#@r.Id</span></td>
                        <td>@(r.Customer is null ? "—" : $"{r.Customer.FirstName} {r.Customer.LastName}")</td>
                        <td>@r.StartDate.ToString("g") – @r.EndDate.ToString("g")</td>
                        <td><partial name="_StatusChip" model="@(UiDisplayHelper.ReservationChipClass(r.Status), UiDisplayHelper.ReservationStatusLabel(r.Status))" /></td>
                        <td class="row-actions">
                            <a asp-controller="Reservation" asp-action="Details" asp-route-id="@r.Id" class="btn btn-ghost btn-sm">Detalji</a>
                            <a asp-controller="Reservation" asp-action="Edit" asp-route-id="@r.Id" asp-route-returnUrl="@vehicleReturn" class="btn btn-ghost btn-sm">Uredi</a>
                        </td>
                    </tr>
                }
                </tbody>
            </table>
        </div>
    }
</div>

<div id="servisi" class="tab-panel">
    <div class="tab-toolbar">
        <h3 class="tab-toolbar-title">Servisna povijest</h3>
        <a asp-controller="ServiceRecord" asp-action="Create" asp-route-vehicleId="@Model.Id" asp-route-returnUrl="@vehicleReturn" class="btn btn-primary btn-sm">+ Novi servis</a>
    </div>
    @if (!Model.ServiceRecords.Any())
    {
        <p class="tab-empty">Nema evidentiranih servisa.</p>
    }
    else
    {
        <div class="table-wrap">
            <table class="data-table">
                <thead><tr><th>Datum</th><th>Status</th><th>Opis</th><th>Trošak</th><th>Akcije</th></tr></thead>
                <tbody>
                @foreach (var s in Model.ServiceRecords.OrderByDescending(x => x.ServiceDate))
                {
                    <tr>
                        <td>@s.ServiceDate.ToString("g")</td>
                        <td><partial name="_StatusChip" model="@(UiDisplayHelper.ServiceChipClass(s.Status), s.Status.ToString())" /></td>
                        <td>@s.Description</td>
                        <td>@s.Cost.ToString("N2") €</td>
                        <td class="row-actions">
                            <a asp-controller="ServiceRecord" asp-action="Details" asp-route-id="@s.Id" class="btn btn-ghost btn-sm">Detalji</a>
                            <a asp-controller="ServiceRecord" asp-action="Edit" asp-route-id="@s.Id" asp-route-returnUrl="@vehicleReturn" class="btn btn-ghost btn-sm">Uredi</a>
                        </td>
                    </tr>
                }
                </tbody>
            </table>
        </div>
    }
</div>

<div id="dokumenti" class="tab-panel">
    <div class="tab-toolbar">
        <h3 class="tab-toolbar-title">Dokumenti vozila</h3>
        <button type="button" class="btn btn-primary btn-sm" id="btnNewDocument">+ Novi dokument</button>
    </div>
    <form id="vehicleDocDz"
          asp-controller="Vehicle"
          asp-action="UploadAttachment"
          asp-route-vehicleId="@Model.Id"
          enctype="multipart/form-data"
          class="dropzone attachment-dropzone vehicle-doc-dropzone is-collapsed">
    </form>
    <div id="attachmentList">
        <partial name="_AttachmentList" model="@attachments" />
    </div>
</div>

@section Scripts {
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/dropzone/5.9.3/min/dropzone.min.css" />
    <script src="https://cdnjs.cloudflare.com/ajax/libs/dropzone/5.9.3/min/dropzone.min.js"></script>
    <script>
        const vehicleId = @Model.Id;

        document.querySelectorAll('.tab-btn').forEach(btn => {
            btn.addEventListener('click', () => {
                document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
                document.querySelectorAll('.tab-panel').forEach(p => p.classList.remove('active'));
                btn.classList.add('active');
                document.getElementById(btn.dataset.tab)?.classList.add('active');
            });
        });

        function loadAttachments() {
            $("#attachmentList").load("@Url.Action("GetAttachments", "Vehicle", new { vehicleId = Model.Id })");
        }

        function deleteAttachment(id) {
            if (!confirm("Obrisati dokument?")) return;
            $.post("@Url.Action("DeleteAttachment", "Vehicle")", { id }, function () {
                loadAttachments();
                const docTab = document.querySelector('.tab-btn[data-tab="dokumenti"]');
                if (docTab) {
                    const count = document.querySelectorAll('#attachmentList tbody tr').length;
                    docTab.textContent = `Dokumenti (${count})`;
                }
            });
        }

        Dropzone.autoDiscover = false;
        $(function () {
            const dzEl = document.getElementById("vehicleDocDz");
            const btnNew = document.getElementById("btnNewDocument");
            let dz;

            if (dzEl) {
                dz = new Dropzone("#vehicleDocDz", {
                    paramName: "file",
                    maxFilesize: 10,
                    acceptedFiles: ".pdf,.jpg,.jpeg,.png",
                    dictDefaultMessage: "Povuci datoteke ovdje ili klikni za odabir (PDF, JPG, PNG · max 10 MB)",
                    success: function () {
                        loadAttachments();
                        dzEl.classList.add("is-collapsed");
                        const docTab = document.querySelector('.tab-btn[data-tab="dokumenti"]');
                        if (docTab) {
                            const count = document.querySelectorAll('#attachmentList tbody tr').length;
                            docTab.textContent = `Dokumenti (${count})`;
                        }
                    }
                });
            }

            btnNew?.addEventListener("click", () => {
                dzEl?.classList.remove("is-collapsed");
                dz?.hiddenFileInput?.click();
            });
        });
    </script>
}

