(function initReservationTabFilters() {
    const table = document.getElementById('vehicleResTable');
    if (!table) return;

    const tbody = table.querySelector('tbody');
    const qInput = document.getElementById('resFilterQ');
    const typeSelect = document.getElementById('resFilterType');
    const statusSelect = document.getElementById('resFilterStatus');
    const sortSelect = document.getElementById('resFilterSort');
    const meta = document.getElementById('resFilterMeta');
    const emptyEl = document.getElementById('resFilterEmpty');
    const tableWrap = document.getElementById('vehicleResTableWrap');
    const sortHeaders = table.querySelectorAll('th.sortable');

    const rows = () => Array.from(tbody.querySelectorAll('tr'));
    let sortKey = 'date';
    let sortDir = 'desc';

    function parseSort(value) {
        const [key, dir] = value.split('-');
        return { key, dir: dir === 'asc' ? 'asc' : 'desc' };
    }

    function syncSortUi() {
        sortHeaders.forEach(h => h.classList.remove('sort-asc', 'sort-desc'));
        const active = table.querySelector(`th.sortable[data-sort="${sortKey}"]`);
        active?.classList.add(sortDir === 'asc' ? 'sort-asc' : 'sort-desc');
        if (sortSelect) {
            const optionValue = `${sortKey}-${sortDir}`;
            if ([...sortSelect.options].some(o => o.value === optionValue))
                sortSelect.value = optionValue;
        }
    }

    function sortRows() {
        const sorted = rows().sort((a, b) => {
            let cmp = 0;
            if (sortKey === 'date')
                cmp = new Date(a.dataset.date) - new Date(b.dataset.date);
            else if (sortKey === 'customer')
                cmp = (a.dataset.customer || '').localeCompare(b.dataset.customer || '', 'hr');
            else if (sortKey === 'status')
                cmp = a.dataset.status.localeCompare(b.dataset.status, 'hr');
            else if (sortKey === 'id')
                cmp = (parseInt(a.dataset.id, 10) || 0) - (parseInt(b.dataset.id, 10) || 0);
            return sortDir === 'asc' ? cmp : -cmp;
        });
        sorted.forEach(row => tbody.appendChild(row));
    }

    function applyFilters() {
        const q = (qInput?.value || '').trim().toLowerCase();
        const type = typeSelect?.value || '';
        const status = statusSelect?.value || '';
        let visible = 0;
        const total = rows().length;

        rows().forEach(row => {
            const idText = row.dataset.id || '';
            const customer = row.dataset.customer || '';
            const haystack = `${idText} ${customer} ${row.textContent}`.toLowerCase();
            const matchQ = !q || haystack.includes(q);
            const matchType = !type || row.dataset.eventType === type;
            const matchStatus = !status || row.dataset.status === status;
            const show = matchQ && matchType && matchStatus;
            row.hidden = !show;
            if (show) visible++;
        });

        if (meta)
            meta.textContent = visible === total ? `${total} stavki` : `Prikazano ${visible} od ${total}`;
        if (emptyEl) emptyEl.hidden = visible > 0;
        if (tableWrap) tableWrap.hidden = visible === 0;
    }

    function refresh() {
        sortRows();
        applyFilters();
    }

    qInput?.addEventListener('input', applyFilters);
    typeSelect?.addEventListener('change', applyFilters);
    statusSelect?.addEventListener('change', applyFilters);
    sortSelect?.addEventListener('change', () => {
        const parsed = parseSort(sortSelect.value);
        sortKey = parsed.key;
        sortDir = parsed.dir;
        syncSortUi();
        refresh();
    });

    sortHeaders.forEach(th => {
        th.addEventListener('click', () => {
            const key = th.dataset.sort;
            if (sortKey === key)
                sortDir = sortDir === 'asc' ? 'desc' : 'asc';
            else {
                sortKey = key;
                sortDir = th.dataset.sortDefault === 'asc' ? 'asc' : 'desc';
            }
            syncSortUi();
            refresh();
        });
    });

    syncSortUi();
    refresh();
})();

