using CarRent.Model.Enums;

namespace CarRent.Web.Services;

public static class FleetLifecycleRules
{
    /// <summary>
    /// Vraća novi status rezervacije ili null ako se ne mijenja.
    /// Nacrt, otkazane i već završene rezervacije ostaju netaknute.
    /// </summary>
    public static ReservationStatus? ResolveReservationStatus(
        ReservationStatus current,
        DateTime start,
        DateTime end,
        DateTime today)
    {
        if (current is ReservationStatus.Cancelled or ReservationStatus.Completed or ReservationStatus.Draft)
            return null;

        var startDay = start.Date;
        var endDay = end.Date;
        var todayDay = today.Date;

        if (endDay < todayDay)
            return ReservationStatus.Completed;

        if (startDay <= todayDay && todayDay <= endDay)
            return current == ReservationStatus.Active ? null : ReservationStatus.Active;

        if (startDay > todayDay && current == ReservationStatus.Active)
            return ReservationStatus.Confirmed;

        return null;
    }

    /// <summary>
    /// Vraća novi status servisa ili null ako se ne mijenja.
    /// </summary>
    public static ServiceStatus? ResolveServiceStatus(
        ServiceStatus current,
        DateTime serviceDate,
        DateTime today)
    {
        if (current is ServiceStatus.Cancelled or ServiceStatus.Completed)
            return null;

        var serviceDay = serviceDate.Date;
        var todayDay = today.Date;

        if (current == ServiceStatus.InProgress && serviceDay < todayDay)
            return ServiceStatus.Completed;

        if (current == ServiceStatus.Planned && serviceDay <= todayDay)
            return ServiceStatus.InProgress;

        return null;
    }

    public static void ApplyReservationLifecycle(Reservation reservation, DateTime? today = null)
    {
        var next = ResolveReservationStatus(
            reservation.Status,
            reservation.StartDate,
            reservation.EndDate,
            today ?? DateTime.Today);

        if (next is not null)
            reservation.Status = next.Value;
    }

    public static void ApplyServiceLifecycle(ServiceRecord service, DateTime? today = null)
    {
        var next = ResolveServiceStatus(
            service.Status,
            service.ServiceDate,
            today ?? DateTime.Today);

        if (next is not null)
            service.Status = next.Value;
    }
}

using CarRent.DAL;
using CarRent.Model.Enums;
using Microsoft.EntityFrameworkCore;

namespace CarRent.Web.Services;

public sealed record FleetLifecycleSyncResult(int ReservationUpdates, int ServiceUpdates)
{
    public int TotalUpdates => ReservationUpdates + ServiceUpdates;
}

public sealed class FleetLifecycleService(CarRentDbContext db, ILogger<FleetLifecycleService> logger)
{
    public async Task<FleetLifecycleSyncResult> SyncAsync(CancellationToken cancellationToken = default)
    {
        var today = DateTime.Today;
        var reservationUpdates = 0;
        var serviceUpdates = 0;

        var reservations = await db.Reservations
            .Where(r => r.Status != ReservationStatus.Cancelled
                        && r.Status != ReservationStatus.Completed
                        && r.Status != ReservationStatus.Draft)
            .ToListAsync(cancellationToken);

        foreach (var reservation in reservations)
        {
            var next = FleetLifecycleRules.ResolveReservationStatus(
                reservation.Status,
                reservation.StartDate,
                reservation.EndDate,
                today);

            if (next is null || next == reservation.Status)
                continue;

            logger.LogInformation(
                "Rezervacija #{Id}: {From} → {To}",
                reservation.Id,
                reservation.Status,
                next);

            reservation.Status = next.Value;
            reservationUpdates++;
        }

        var services = await db.ServiceRecords
            .Where(s => s.Status != ServiceStatus.Cancelled && s.Status != ServiceStatus.Completed)
            .ToListAsync(cancellationToken);

        foreach (var service in services)
        {
            var next = FleetLifecycleRules.ResolveServiceStatus(
                service.Status,
                service.ServiceDate,
                today);

            if (next is null || next == service.Status)
                continue;

            logger.LogInformation(
                "Servis #{Id}: {From} → {To}",
                service.Id,
                service.Status,
                next);

            service.Status = next.Value;
            serviceUpdates++;
        }

        if (reservationUpdates + serviceUpdates > 0)
            await db.SaveChangesAsync(cancellationToken);

        return new FleetLifecycleSyncResult(reservationUpdates, serviceUpdates);
    }
}

using CarRent.Web.Services;

namespace CarRent.Web.Middleware;

public sealed class FleetLifecycleMiddleware(RequestDelegate next, ILogger<FleetLifecycleMiddleware> logger)
{
    private static readonly TimeSpan SyncInterval = TimeSpan.FromMinutes(5);
    private static DateTime _lastSyncUtc = DateTime.MinValue;
    private static readonly SemaphoreSlim SyncGate = new(1, 1);

    public async Task InvokeAsync(HttpContext context, FleetLifecycleService lifecycle)
    {
        if (ShouldTrySync(context))
            await TrySyncAsync(lifecycle, context.RequestAborted);

        await next(context);
    }

    private static bool ShouldTrySync(HttpContext context)
    {
        if (!HttpMethods.IsGet(context.Request.Method) && !HttpMethods.IsHead(context.Request.Method))
            return false;

        var path = context.Request.Path;
        if (path.StartsWithSegments("/css")
            || path.StartsWithSegments("/js")
            || path.StartsWithSegments("/lib")
            || path.StartsWithSegments("/uploads")
            || path.StartsWithSegments("/Identity"))
            return false;

        return true;
    }

    private async Task TrySyncAsync(FleetLifecycleService lifecycle, CancellationToken cancellationToken)
    {
        if (DateTime.UtcNow - _lastSyncUtc < SyncInterval)
            return;

        await SyncGate.WaitAsync(cancellationToken);
        try
        {
            if (DateTime.UtcNow - _lastSyncUtc < SyncInterval)
                return;

            var result = await lifecycle.SyncAsync(cancellationToken);
            _lastSyncUtc = DateTime.UtcNow;

            if (result.TotalUpdates > 0)
            {
                logger.LogInformation(
                    "Automatska sinkronizacija statusa: {Reservations} rezervacija, {Services} servisa",
                    result.ReservationUpdates,
                    result.ServiceUpdates);
            }
        }
        finally
        {
            SyncGate.Release();
        }
    }
}

