using CarRent.Model.Entities;
using CarRent.Model.Enums;

namespace CarRent.Web.Services;

public sealed class ReservationLifecycleChange
{
    public ReservationStatus? NewStatus { get; init; }
    public bool SuggestMileageUpdate { get; init; }
    public bool IsNoShowCancellation { get; init; }
    public bool IsDraftExpiry { get; init; }
    public bool IsDraftReminder { get; init; }

    public bool HasStatusChange => NewStatus is not null;
}

public static class FleetLifecycleRules
{
    public static ReservationLifecycleChange EvaluateReservation(
        Reservation reservation,
        FleetLifecycleOptions options,
        DateTime now)
    {
        if (reservation.Status == ReservationStatus.Draft)
            return EvaluateDraft(reservation, options, now);

        if (reservation.Status is ReservationStatus.Cancelled or ReservationStatus.Completed)
            return new ReservationLifecycleChange();

        var noShow = ResolveNoShow(reservation.Status, reservation.StartDate, now, options.NoShowHoursAfterStart);
        if (noShow == ReservationStatus.Cancelled)
        {
            return new ReservationLifecycleChange
            {
                NewStatus = ReservationStatus.Cancelled,
                IsNoShowCancellation = true
            };
        }

        var next = ResolveReservationStatus(
            reservation.Status,
            reservation.StartDate,
            reservation.EndDate,
            now.Date);

        if (next == ReservationStatus.Completed)
        {
            return new ReservationLifecycleChange
            {
                NewStatus = ReservationStatus.Completed,
                SuggestMileageUpdate = true
            };
        }

        if (next is not null)
            return new ReservationLifecycleChange { NewStatus = next };

        return new ReservationLifecycleChange();
    }

    public static ReservationStatus? ResolveNoShow(
        ReservationStatus current,
        DateTime start,
        DateTime now,
        int noShowHoursAfterStart)
    {
        if (current != ReservationStatus.Confirmed)
            return null;

        return now > start.AddHours(noShowHoursAfterStart)
            ? ReservationStatus.Cancelled
            : null;
    }

    private static ReservationLifecycleChange EvaluateDraft(
        Reservation reservation,
        FleetLifecycleOptions options,
        DateTime now)
    {
        var ageDays = (now - reservation.CreatedAt).TotalDays;
        if (ageDays >= options.DraftExpiryDays)
        {
            return new ReservationLifecycleChange
            {
                NewStatus = ReservationStatus.Cancelled,
                IsDraftExpiry = true
            };
        }

        var reminderFromDay = options.DraftExpiryDays - options.DraftReminderDaysBeforeExpiry;
        if (ageDays >= reminderFromDay)
        {
            return new ReservationLifecycleChange { IsDraftReminder = true };
        }

        return new ReservationLifecycleChange();
    }

    /// <summary>
    /// Vraća novi status rezervacije ili null ako se ne mijenja.
    /// </summary>
    public static ReservationStatus? ResolveReservationStatus(
        ReservationStatus current,
        DateTime start,
        DateTime end,
        DateTime today)
    {
        if (current is ReservationStatus.Cancelled or ReservationStatus.Completed or ReservationStatus.Draft)
            return null;

        var startDay = start.Date;
        var endDay = end.Date;
        var todayDay = today.Date;

        if (endDay < todayDay)
            return ReservationStatus.Completed;

        if (startDay <= todayDay && todayDay <= endDay)
            return current == ReservationStatus.Active ? null : ReservationStatus.Active;

        if (startDay > todayDay && current == ReservationStatus.Active)
            return ReservationStatus.Confirmed;

        return null;
    }

    public static ServiceStatus? ResolveServiceStatus(
        ServiceStatus current,
        DateTime serviceDate,
        DateTime today)
    {
        if (current is ServiceStatus.Cancelled or ServiceStatus.Completed)
            return null;

        var serviceDay = serviceDate.Date;
        var todayDay = today.Date;

        if (current == ServiceStatus.InProgress && serviceDay < todayDay)
            return ServiceStatus.Completed;

        if (current == ServiceStatus.Planned && serviceDay <= todayDay)
            return ServiceStatus.InProgress;

        return null;
    }

    public static void ApplyReservationLifecycle(
        Reservation reservation,
        FleetLifecycleOptions? options = null,
        DateTime? now = null)
    {
        options ??= new FleetLifecycleOptions();
        now ??= DateTime.Now;

        var change = EvaluateReservation(reservation, options, now.Value);
        if (change.NewStatus is not null)
            reservation.Status = change.NewStatus.Value;

        if (change.SuggestMileageUpdate)
            reservation.MileageUpdateSuggested = true;
    }

    public static void ApplyServiceLifecycle(ServiceRecord service, DateTime? today = null)
    {
        var next = ResolveServiceStatus(
            service.Status,
            service.ServiceDate,
            today ?? DateTime.Today);

        if (next is not null)
            service.Status = next.Value;
    }
}

using CarRent.DAL;
using CarRent.Model.Enums;
using CarRent.Web.Services.Notifications;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Options;

namespace CarRent.Web.Services;

public sealed record FleetLifecycleSyncResult(
    int ReservationUpdates,
    int ServiceUpdates,
    int VehicleHoldUpdates,
    int NotificationsPrepared)
{
    public int TotalUpdates => ReservationUpdates + ServiceUpdates + VehicleHoldUpdates;
}

public sealed class FleetLifecycleService(
    CarRentDbContext db,
    FleetNotificationService notifications,
    IOptions<FleetLifecycleOptions> options,
    ILogger<FleetLifecycleService> logger)
{
    public async Task<FleetLifecycleSyncResult> SyncAsync(CancellationToken cancellationToken = default)
    {
        var now = DateTime.Now;
        var today = now.Date;
        var opts = options.Value;
        var reservationUpdates = 0;
        var serviceUpdates = 0;
        var vehicleHoldUpdates = 0;

        var reservations = await db.Reservations
            .Include(r => r.Customer)
            .Include(r => r.Vehicle)
            .Where(r => r.Status != ReservationStatus.Cancelled && r.Status != ReservationStatus.Completed)
            .ToListAsync(cancellationToken);

        foreach (var reservation in reservations)
        {
            var change = FleetLifecycleRules.EvaluateReservation(reservation, opts, now);

            if (change.IsDraftReminder)
            {
                await notifications.NotifyDraftReminderAsync(
                    reservation.Id,
                    reservation.Customer?.Email ?? string.Empty,
                    reservation.CreatedAt.AddDays(opts.DraftExpiryDays),
                    cancellationToken);
                continue;
            }

            if (!change.HasStatusChange && !change.SuggestMileageUpdate)
                continue;

            if (change.NewStatus is not null && change.NewStatus != reservation.Status)
            {
                logger.LogInformation(
                    "Rezervacija #{Id}: {From} → {To}",
                    reservation.Id,
                    reservation.Status,
                    change.NewStatus);

                reservation.Status = change.NewStatus.Value;
                reservationUpdates++;

                if (change.IsNoShowCancellation)
                {
                    await notifications.NotifyNoShowCancelledAsync(
                        reservation.Id,
                        reservation.Customer?.Email,
                        cancellationToken);
                }

                if (change.IsDraftExpiry)
                    await notifications.NotifyDraftExpiredAsync(reservation.Id, cancellationToken);
            }

            if (change.SuggestMileageUpdate && !reservation.MileageUpdateSuggested)
            {
                reservation.MileageUpdateSuggested = true;
                reservationUpdates++;

                var reg = reservation.Vehicle?.RegistrationNumber ?? $"#{reservation.VehicleId}";
                await notifications.NotifyMileageUpdateSuggestedAsync(
                    reservation.Id,
                    reservation.VehicleId,
                    reg,
                    cancellationToken);
            }
        }

        var services = await db.ServiceRecords
            .Where(s => s.Status != ServiceStatus.Cancelled && s.Status != ServiceStatus.Completed)
            .ToListAsync(cancellationToken);

        foreach (var service in services)
        {
            var next = FleetLifecycleRules.ResolveServiceStatus(service.Status, service.ServiceDate, today);
            if (next is null || next == service.Status)
                continue;

            logger.LogInformation("Servis #{Id}: {From} → {To}", service.Id, service.Status, next);
            service.Status = next.Value;
            serviceUpdates++;
        }

        vehicleHoldUpdates = await SyncVehicleServiceHoldsAsync(cancellationToken);

        if (reservationUpdates + serviceUpdates + vehicleHoldUpdates > 0)
            await db.SaveChangesAsync(cancellationToken);

        var notificationsPrepared = await notifications.PrepareDailyNotificationsAsync(now, cancellationToken);

        return new FleetLifecycleSyncResult(
            reservationUpdates,
            serviceUpdates,
            vehicleHoldUpdates,
            notificationsPrepared);
    }

    private async Task<int> SyncVehicleServiceHoldsAsync(CancellationToken cancellationToken)
    {
        var vehiclesInService = await db.ServiceRecords
            .Where(s => s.Status == ServiceStatus.InProgress)
            .Select(s => s.VehicleId)
            .Distinct()
            .ToListAsync(cancellationToken);

        var inServiceSet = vehiclesInService.ToHashSet();
        var vehicles = await db.Vehicles.ToListAsync(cancellationToken);
        var updates = 0;

        foreach (var vehicle in vehicles)
        {
            var shouldBlock = inServiceSet.Contains(vehicle.Id);

            if (shouldBlock && !vehicle.BlockedByService)
            {
                vehicle.IsActiveBeforeServiceBlock = vehicle.IsActive;
                vehicle.BlockedByService = true;
                vehicle.IsActive = false;
                updates++;
            }
            else if (!shouldBlock && vehicle.BlockedByService)
            {
                vehicle.IsActive = vehicle.IsActiveBeforeServiceBlock;
                vehicle.BlockedByService = false;
                updates++;
            }
        }

        return updates;
    }
}

